// Unit 22 — Nieuws & Media
// Advanced Passive, Indirect Speech & Dutch Media

export default {n:22,lang:"nl",srcLang:"en",track:"v2",title:"Nieuws & Media",sub:"Advanced Passive, Indirect Speech & Dutch Media",icon:"📰",level:"B2.1",color:"#7B5EE8",lessons:[
  {id:"v2u22l1",title:"Het Nieuws",icon:"📰",xp:20,board:true,steps:[
        {type:"intro",title:"Het Nieuws",desc:"News vocabulary is essential for understanding Dutch media. You already know 'het artikel' and 'het rapport' from Unit 16. Now we add the full newsroom vocabulary: journalists, sources, headlines, and the verbs that drive reporting.",goals:["8 core news vocabulary words","Nouns with correct de/het articles","News reporting verbs","Prepare for passive voice in news context"]},
        {type:"teach",trg:"het nieuws",src:"the news",pos:"noun",gender:"n",phonetic:"hut NEEWS",note:"Het-word. Always singular in Dutch.\n'Het nieuws' = the news (never 'de nieuwsen').\n'Het journaal' = TV news broadcast.",example:"A: Heb je het nieuws gezien?\nB: Nee, wat is er gebeurd?\nA: Er was een grote brand in Rotterdam.\nB: Oh nee, dat is verschrikkelijk!",exampleSrc:"A: Have you seen the news?\nB: No, what happened?\nA: There was a big fire in Rotterdam.\nB: Oh no, that's terrible!",funFact:"Germanic cousin of English 'news', German 'Nachrichten (related)'."},
        {type:"teach",trg:"de krant",src:"the newspaper",pos:"noun",gender:"c",phonetic:"duh krahnt",note:"De-word. Plural: 'kranten'.\n'De dagkrant' = daily newspaper.\n'De krant lezen' = to read the newspaper.",example:"A: Lees jij nog de krant?\nB: Ja, ik lees de Volkskrant elke ochtend.\nA: Digitaal of op papier?\nB: Digitaal, dat is makkelijker.",exampleSrc:"A: Do you still read the newspaper?\nB: Yes, I read the Volkskrant every morning.\nA: Digital or on paper?\nB: Digital, that's easier.",funFact:"Germanic cousin of German 'Zeitung (different)'."},
        {type:"teach",trg:"de journalist",src:"the journalist",pos:"noun",gender:"c",phonetic:"duh zhoor-nah-LIST",note:"De-word. Both men and women: 'de journalist'.\n'Een onderzoeksjournalist' = investigative journalist.\n'Journalistiek' = journalism.",example:"A: Wat doet een journalist precies?\nB: Die schrijft artikelen en doet onderzoek.\nA: Klinkt als een drukke baan.\nB: Zeker, vooral bij breaking news!",exampleSrc:"A: What does a journalist do exactly?\nB: They write articles and do research.\nA: Sounds like a busy job.\nB: Definitely, especially with breaking news!",funFact:"latin cousin of English 'journalist', French 'journaliste'."},
        {type:"teach",trg:"de redactie",src:"the editorial team / newsroom",pos:"noun",gender:"c",phonetic:"duh ruh-DAK-see",note:"De-word. 'De hoofdredacteur' = editor-in-chief.\n'De redactievergadering' = editorial meeting.\nKey word for understanding Dutch media structure.",example:"A: Wie beslist welke artikelen worden gepubliceerd?\nB: Dat doet de redactie.\nA: En de hoofdredacteur leidt het team?\nB: Precies, die heeft het laatste woord.",exampleSrc:"A: Who decides which articles get published?\nB: The editorial team does that.\nA: And the editor-in-chief leads the team?\nB: Exactly, they have the final word.",funFact:"latin cousin of English 'redaction (related)', German 'Redaktion'."},
        {type:"teach",trg:"publiceren",src:"to publish",pos:"verb",gender:null,phonetic:"puu-blee-SAY-run",note:"Inseparable (prefix pub-).\nPast participle: gepubliceerd.\n'De publicatie' = the publication.\nPassive very common: 'wordt gepubliceerd'.",example:"A: Wanneer wordt het artikel gepubliceerd?\nB: Morgen in de ochtendkrant.\nA: Online ook?\nB: Ja, tegelijkertijd op de website.",exampleSrc:"A: When will the article be published?\nB: Tomorrow in the morning paper.\nA: Online too?\nB: Yes, simultaneously on the website.",funFact:"latin cousin of English 'publish', French 'publier'."},
        {type:"teach",trg:"melden",src:"to report / announce",pos:"verb",gender:null,phonetic:"MEL-dun",note:"You saw this in Unit 18.\nNow in its natural habitat: news reporting.\n'Bronnen melden dat...' = Sources report that...\n'Een melding' = a report/notification.",example:"A: De NOS meldt dat de minister aftreedt.\nB: Echt waar? Wanneer?\nA: Vandaag nog, volgens het bericht.\nB: Dat is groot nieuws!",exampleSrc:"A: NOS reports that the minister is resigning.\nB: Really? When?\nA: Today still, according to the report.\nB: That's big news!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"rapporteren",src:"to report (formally)",pos:"verb",gender:null,phonetic:"rap-por-TAY-run",note:"More formal than 'melden'.\n'Rapporteren over' = to report on.\n'Het rapport' = the report (noun).\nCommon in official and international news.",example:"A: De correspondent rapporteert vanuit Brussel.\nB: Wat is de situatie daar?\nA: Er wordt onderhandeld over een nieuw akkoord.\nB: Spannend!",exampleSrc:"A: The correspondent reports from Brussels.\nB: What's the situation there?\nA: Negotiations about a new agreement are taking place.\nB: Exciting!",funFact:"latin cousin of English 'report', French 'rapporter'."},
        {type:"teach",trg:"de headline",src:"the headline",pos:"noun",gender:"c",phonetic:"duh HED-line",note:"De-word. Also: 'de kop' (Dutch native term).\n'De koppen' = the headlines.\n'Koppen lezen' = to scan the headlines.\nBoth 'headline' and 'kop' are used.",example:"A: Heb je de headline gelezen?\nB: Ja, nogal schokkend!\nA: De media overdrijven soms.\nB: Dat is waar, je moet kritisch blijven.",exampleSrc:"A: Have you read the headline?\nB: Yes, quite shocking!\nA: The media exaggerate sometimes.\nB: That's true, you have to stay critical.",funFact:"Germanic cousin of English 'headline'."},
        {type:"tip",title:"📰 Nieuws Lezen: Key Phrases",text:"When discussing news in Dutch, you need these patterns:\n\nVolgens het bericht... = According to the report...\nUit onderzoek blijkt dat... = Research shows that...\nBronnen melden dat... = Sources report that...\nEr wordt gemeld dat... = It is reported that...\nHet artikel gaat over... = The article is about...\n\nNotice how many use passive voice or indirect speech.\nNews Dutch is HEAVY on both constructions.\nThat's why we combine them in this unit!"},
        {type:"mc",q:"Which article does 'nieuws' take?",opts:["de","het","een","geen"],ans:"het",hint:"This noun is always singular in Dutch"},
        {type:"fb",opts:["journalist","redactie","krant","headline"],hint:"The person who writes news articles",s:"De ___ schrijft artikelen en doet onderzoek.",a:"journalist"},
        {type:"match",pairs:[{trg:"het nieuws",src:"the news"},{trg:"de krant",src:"the newspaper"},{trg:"de journalist",src:"the journalist"},{trg:"de redactie",src:"the editorial team"}]},
        {type:"mc",q:"'De NOS meldt dat de minister aftreedt.' What does 'melden' mean here?",opts:["To warn","To report/announce","To publish","To explain"],ans:"To report/announce",hint:"A business-register verb meaning to ___ or ___"},
        {type:"fb",opts:["gepubliceerd","geschreven","gemeld","gelezen"],hint:"Past participle of publiceren in passive construction",s:"Het artikel wordt morgen ___.",a:"gepubliceerd"},
        {type:"mc",q:"'Rapporteren' is more ___ than 'melden'.",opts:["casual","formal","common","old-fashioned"],ans:"formal",hint:"Official and international reporting"},
        {type:"drag_fill",hint:"The correspondent reports. The editorial team decides.",s:"De {1} rapporteert vanuit Brussel. De {2} beslist welke artikelen worden gepubliceerd.",blanks:{"1":"correspondent","2":"redactie"},pool:["correspondent","redactie","journalist","krant"]},
        {type:"fb",opts:["melden","publiceren","rapporteren","schrijven"],hint:"Bronnen _____ dat: common news phrase",s:"Bronnen ___ dat er een nieuw akkoord komt.",a:"melden"}
  ]},
  {id:"v2u22l2",title:"Media & Verslaggeving",icon:"🎙️",xp:20,board:true,steps:[
        {type:"intro",title:"Media & Verslaggeving",desc:"Beyond newspapers: the full Dutch media landscape. Interviews, correspondents, sources, and the new media formats. Plus key adjectives for evaluating news quality.",goals:["8 media and reporting vocabulary words","Interview, correspondent, bron, betrouwbaar, objectief","Modern media: uitzending, documentaire, podcast, livestream","Evaluate news credibility in Dutch"]},
        {type:"teach",trg:"het interview",src:"the interview",pos:"noun",gender:"n",phonetic:"hut IN-tur-vyoo",note:"Het-word. 'Een interview afnemen' = to conduct an interview.\n'Een interview geven' = to give an interview.\nPronounced the English way in Dutch.",example:"A: Heb je het interview met de minister gezien?\nB: Ja, de journalist stelde goede vragen.\nA: Vond je het eerlijk?\nB: Redelijk, maar sommige vragen werden ontweken.",exampleSrc:"A: Did you see the interview with the minister?\nB: Yes, the journalist asked good questions.\nA: Did you find it fair?\nB: Fairly, but some questions were dodged.",funFact:"latin cousin of English 'interview', French 'interview'."},
        {type:"teach",trg:"de correspondent",src:"the correspondent",pos:"noun",gender:"c",phonetic:"duh kor-res-pon-DENT",note:"De-word. A journalist stationed abroad.\n'De buitenlandcorrespondent' = foreign correspondent.\nNOS has correspondents worldwide.\n'Verslaggeving ter plaatse' = reporting on the scene.",example:"A: De correspondent in Washington meldt onrust.\nB: Hoe lang zit zij daar al?\nA: Al drie jaar, geloof ik.\nB: Dan kent zij de situatie goed.",exampleSrc:"A: The correspondent in Washington reports unrest.\nB: How long has she been there?\nA: Three years, I think.\nB: Then she knows the situation well.",funFact:"latin cousin of English 'correspondent', French 'correspondant'."},
        {type:"teach",trg:"de bron",src:"the source",pos:"noun",gender:"c",phonetic:"duh bron",note:"De-word. Also: 'spring/well' (literal meaning).\n'Betrouwbare bronnen' = reliable sources.\n'Anonieme bron' = anonymous source.\n'Bronnenonderzoek' = source research.",example:"A: Hoeveel bronnen heeft de journalist gebruikt?\nB: Minstens drie, dat is de standaard.\nA: En als een bron anoniem wil blijven?\nB: Dan beschermt de journalist die bron.",exampleSrc:"A: How many sources did the journalist use?\nB: At least three, that's the standard.\nA: And if a source wants to remain anonymous?\nB: Then the journalist protects that source.",funFact:"Germanic cousin of German 'Brunnen (related)'."},
        {type:"teach",trg:"betrouwbaar",src:"reliable / trustworthy",pos:"noun",gender:null,phonetic:"buh-TROW-bahr",note:"'Betrouwbaar' = reliable/trustworthy.\n'Onbetrouwbaar' = unreliable.\n'De betrouwbaarheid' = reliability.\nKey word for media literacy!",example:"A: Is die website betrouwbaar?\nB: Ik zou voorzichtig zijn.\nA: Hoe herken je nepnieuws?\nB: Check altijd de bronnen!",exampleSrc:"A: Is that website reliable?\nB: I would be careful.\nA: How do you recognize fake news?\nB: Always check the sources!",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"objectief",src:"objective / unbiased",pos:"noun",gender:null,phonetic:"ob-yek-TEEF",note:"'Objectief' vs 'subjectief' (subjective).\n'Objectieve verslaggeving' = objective reporting.\nKey concept in journalism.\n'De objectiviteit' = objectivity.",example:"A: Denk je dat de NOS objectief is?\nB: Ze proberen het wel, maar niemand is perfect.\nA: Subjectiviteit is menselijk.\nB: Daarom is het goed om meerdere bronnen te lezen.",exampleSrc:"A: Do you think NOS is objective?\nB: They try, but nobody's perfect.\nA: Subjectivity is human.\nB: That's why it's good to read multiple sources.",funFact:"latin cousin of English 'objective', French 'objectif'."},
        {type:"teach",trg:"de uitzending",src:"the broadcast",pos:"noun",gender:"c",phonetic:"duh OWT-zen-ding",note:"De-word. From 'uitzenden' (to broadcast).\n'Een live uitzending' = a live broadcast.\n'De uitzending werd onderbroken' = the broadcast was interrupted.\nSeparable: 'De NOS zendt uit om 8 uur.'",example:"A: Heb je de uitzending van gisteravond gezien?\nB: De documentaire over klimaatverandering?\nA: Ja, die was echt indrukwekkend.\nB: Ik ga hem vanavond terugkijken.",exampleSrc:"A: Did you see last night's broadcast?\nB: The documentary about climate change?\nA: Yes, it was really impressive.\nB: I'm going to rewatch it tonight.",funFact:"A de-word (common gender). About 2/3 of Dutch nouns use 'de'. All plurals always use 'de'."},
        {type:"teach",trg:"de documentaire",src:"the documentary",pos:"noun",gender:"c",phonetic:"duh do-ku-men-TAI-ruh",note:"De-word. 'Een documentaire maken' = to make a documentary.\nNPO (Nederlandse Publieke Omroep) = Dutch public broadcasting.\nVery popular format in the Netherlands.",example:"A: Ken je een goede documentaire?\nB: Er is een nieuwe op NPO over de Deltawerken.\nA: Waar gaat die over?\nB: Over hoe Nederland zichzelf beschermt tegen water.",exampleSrc:"A: Do you know a good documentary?\nB: There's a new one on NPO about the Delta Works.\nA: What's it about?\nB: About how the Netherlands protects itself against water.",funFact:"latin cousin of English 'documentary', French 'documentaire'."},
        {type:"teach",trg:"de podcast",src:"the podcast",pos:"noun",gender:"c",phonetic:"duh POD-kest",note:"De-word. 'Een podcast luisteren' = to listen to a podcast.\n'De Dag' and 'NRC Vandaag' are popular Dutch news podcasts.\nPodcasts are huge in the Netherlands.",example:"A: Luister jij naar podcasts?\nB: Ja, ik luister elke dag tijdens het fietsen.\nA: Welke raad je aan?\nB: De Dag, dat is een nieuwspodcast van de NOS.",exampleSrc:"A: Do you listen to podcasts?\nB: Yes, I listen every day while cycling.\nA: Which one do you recommend?\nB: De Dag, that's a news podcast from NOS.",funFact:"Germanic cousin of English 'podcast'."},
        {type:"tip",title:"📱 Oud & Nieuw Media",text:"Traditional media:\nde krant = newspaper\nhet journaal = TV news\nde radio = radio\nde uitzending = broadcast\n\nNew media:\nde podcast = podcast\nde livestream = livestream\nsociale media = social media\nde blog = blog\n\nKey difference in Dutch:\n'De media ZIJN...' (plural verb!).\nDutch treats 'media' as plural.\n'De media hebben gerapporteerd dat...' (not 'heeft')."},
        {type:"mc",q:"'De bron' in news context means:",opts:["The bridge","The bread","The source","The brother"],ans:"The source",hint:"Betrouwbare bronnen = reliable sources"},
        {type:"fb",opts:["betrouwbaar","objectief","interessant","populair"],hint:"Is die website te vertrouwen?",s:"Is die website ___? Je moet de bronnen checken.",a:"betrouwbaar"},
        {type:"match",pairs:[{trg:"het interview",src:"the interview"},{trg:"de correspondent",src:"the correspondent"},{trg:"de bron",src:"the source"},{trg:"de uitzending",src:"the broadcast"}]},
        {type:"mc",q:"'Objectieve verslaggeving' means:",opts:["Popular reporting","Fast reporting","Unbiased reporting","Expensive reporting"],ans:"Unbiased reporting",hint:"Objectief = objective/___"},
        {type:"fb",opts:["documentaire","podcast","headline","bron"],hint:"A factual film or TV program (de _____)",s:"Heb je de ___ over klimaatverandering gezien?",a:"documentaire"},
        {type:"mc",q:"In Dutch, 'de media' takes which verb form?",opts:["Singular: is/heeft","Plural: zijn/hebben","Either one","No verb needed"],ans:"Plural: zijn/hebben",hint:"De media ___, de media ___"},
        {type:"drag_fill",hint:"The journalist asked questions. The correspondent reports from abroad.",s:"De {1} stelde goede vragen. De {2} meldt vanuit het buitenland.",blanks:{"1":"journalist","2":"correspondent"},pool:["journalist","correspondent","redactie","bron"]},
        {type:"fb",opts:["podcasts","uitzendingen","kranten","interviews"],hint:"Audio shows you stream or download",s:"Luister jij naar ___? De Dag is een goede nieuwspodcast.",a:"podcasts"}
  ]},
  {id:"v2u22l3",title:"Werd Gemeld & Is Gemeld",icon:"📐",xp:25,board:true,steps:[
        {type:"intro",title:"Werd Gemeld & Is Gemeld",desc:"In Unit 16, you learned 'wordt + past participle' for present passive. Now we go deeper: past passive with 'werd/werden', the result passive with 'is/zijn + past participle', and the crucial difference between 'worden' and 'zijn' passives.",goals:["werd/werden + PP = past passive (process)","is/zijn + PP = result passive (state)","worden vs zijn passive distinction","door-agent in complex passive sentences"]},
        {type:"tip",title:"📐 Passive Timeline",text:"You know present passive:\nDe brief wordt geschreven. (is being written)\n\nNow add PAST passive:\nDe brief werd geschreven. (was being written)\nDe brieven werden geschreven. (were being written)\n\nAnd RESULT passive:\nDe brief is geschreven. (has been written = DONE)\nDe brieven zijn geschreven. (have been written = DONE)\n\nThe difference:\nwordt/werd = PROCESS (happening/was happening)\nis/zijn = RESULT (it's done, finished)\n\n'Het artikel wordt geschreven.' = being written now\n'Het artikel werd geschreven.' = was being written\n'Het artikel is geschreven.' = it's finished, ready"},
        {type:"verb_table",title:"Worden  -  Passive Auxiliary",note:"WORDEN passive = process (ongoing action).\nZIJN passive = result (completed state).\nThis is the key distinction at this level!",deepDive:{
          title:"When to use which?",
          text:"Think of it as a camera:\n\nWORDEN = filming the action:\n'De deur wordt geopend.' = Someone is opening the door (we see the process).\n'De deur werd geopend.' = Someone was opening the door.\n\nZIJN = taking a photo of the result:\n'De deur is geopend.' = The door is open (result visible now).\n\nReal news examples:\n'Het akkoord werd getekend door beide partijen.' = The agreement was being signed by both parties (process, we watch it happen).\n'Het akkoord is getekend.' = The agreement has been signed (done, result).\n\nThis distinction exists in German too (werden vs sein passive) but NOT in English. English 'was written' is ambiguous. Dutch is precise."
        },groups:[
          {
            label:"Present (process now)",
            rows:[{pronoun:"het artikel",form:"wordt geschreven",src:"is being written"},{pronoun:"de artikelen",form:"worden geschreven",src:"are being written"}]
          },
          {
            label:"Past (process then)",
            rows:[{pronoun:"het artikel",form:"werd geschreven",src:"was being written"},{pronoun:"de artikelen",form:"werden geschreven",src:"were being written"}]
          },
          {
            label:"Result (state now)",
            rows:[{pronoun:"het artikel",form:"is geschreven",src:"has been written (done)"},{pronoun:"de artikelen",form:"zijn geschreven",src:"have been written (done)"}]
          }
        ],label:"All tenses of worden in passive"},
        {type:"tip",title:"📐 Door-Agent in Complex Sentences",text:"Simple door-agent (you know this from U16):\nHet artikel werd geschreven door de journalist.\n\nComplex door-agent (new at this level):\nHet besluit werd genomen door de minister\nna overleg met de Tweede Kamer.\n= The decision was made by the minister\nafter consultation with the House of Representatives.\n\nPassive + subordinate clause:\nEr werd gemeld dat de fabriek wordt gesloten.\n= It was reported that the factory is being closed.\n\nStacked passives (common in news):\nHet rapport dat werd geschreven door de commissie\nis vandaag gepubliceerd.\n= The report that was written by the committee\nwas published today."},
        {type:"mc",q:"'Het artikel werd geschreven.' This is:",opts:["Present passive","Past passive (process)","Result passive","Future passive"],ans:"Past passive (process)",hint:"Werd = ___ tense of worden (___)"},
        {type:"fb",opts:["is","werd","wordt","had"],hint:"Result/state passive: the signing has been completed",s:"Het akkoord ___ getekend. (result: it's done)",a:"is"},
        {type:"mc",q:"'Worden' passive focuses on the ___, 'zijn' passive on the ___.",opts:["result, process","process, result","past, present","present, future"],ans:"process, result",hint:"Worden = filming the action. Zijn = photo of the ___."},
        {type:"drag_fill",hint:"Yesterday = process (werd). Now finished = result (is).",s:"Het artikel {1} gisteren geschreven. Het artikel {2} nu af.",blanks:{"1":"werd","2":"is"},pool:["werd","is","wordt","was"]},
        {type:"fb",opts:["werden","werd","zijn","was"],hint:"Plural subject + past tense of the passive auxiliary",s:"De brieven ___ geschreven door de studenten. (past process)",a:"werden"},
        {type:"mc",q:"'De deur is geopend.' means:",opts:["The door is being opened right now","The door was being opened","The door is open (result)","The door will be opened"],ans:"The door is open (result)",hint:"Zijn passive = result/state"},
        {type:"fb",opts:["werd","is","wordt","waren"],hint:"Past passive process: which auxiliary?",s:"Het besluit ___ genomen door de minister na overleg.",a:"werd"},
        {type:"drag_fill",hint:"Plural past process. Plural result: they are now done.",s:"De artikelen {1} geschreven door het team. Ze {2} nu klaar.",blanks:{"1":"werden","2":"zijn"},pool:["werden","zijn","werd","is"]},
        {type:"mc",q:"'Er werd gemeld dat de fabriek wordt gesloten.' How many passives?",opts:["Zero","One","Two","Three"],ans:"Two",hint:"werd gemeld (past passive) + wordt gesloten (present passive)"},
        {type:"fb",opts:["werd","is","wordt","waren"],hint:"Past process passive: _____ geschreven",s:"Het rapport dat ___ geschreven door de commissie is gepubliceerd.",a:"werd"},
        {type:"match",pairs:[
          {trg:"wordt geschreven",src:"is being written (present)"},
          {trg:"werd geschreven",src:"was being written (past)"},
          {trg:"is geschreven",src:"has been written (result)"},
          {trg:"werden geschreven",src:"were being written (plural past)"}
        ]},
        {type:"mc",q:"'De wet is aangenomen.' focuses on:",opts:["The process of voting","The result: the law is now adopted","Who voted","When it happened"],ans:"The result: the law is now adopted",hint:"Zijn passive = ___/completed state"},
        {type:"fb",opts:["werden","werd","zijn","is"],hint:"Multiple measures, past process auxiliary",s:"De maatregelen ___ genomen na lang overleg. (past process, plural)",a:"werden"},
        {type:"drag_fill",hint:"The law IS adopted (result). The rules WERE expected (past process).",s:"De wet {1} aangenomen. De regels {2} al langer verwacht.",blanks:{"1":"is","2":"werden"},pool:["is","werden","werd","zijn"]}
  ]},
  {id:"v2u22l4",title:"Zei de Minister",icon:"🗣️",xp:25,board:true,steps:[
        {type:"intro",title:"Zei de Minister",desc:"You learned the basics of indirect speech in Unit 18. Now we apply it in its natural context: news reporting. Politicians say things, journalists report them. Passive and indirect speech combine constantly in Dutch news.",goals:["Review: hij zei dat + tense backshift","Indirect speech in news context","Combine indirect speech + passive voice","Impersonal er-passive with modals in reporting"]},
        {type:"tip",title:"🗣️ Indirect Speech in the News",text:"News is ALL indirect speech:\n\nDe minister zei dat het plan wordt uitgevoerd.\n= The minister said that the plan is being implemented.\n\nDe woordvoerder meldde dat er maatregelen\nworden genomen.\n= The spokesperson reported that measures\nare being taken.\n\nDe expert waarschuwde dat de situatie\nernstiger werd.\n= The expert warned that the situation\nwas becoming more serious.\n\nVolgens de premier moet er meer worden geinvesteerd.\n= According to the PM, more needs to be invested.\n\nNotice: passive + indirect speech = standard Dutch news."},
        {type:"tip",title:"📐 Er-Passive with Modals",text:"Impersonal er-passive (from U14) + modal verbs:\n\nEr moet worden ingegrepen.\n= Action must be taken. (literally: there must be intervened)\n\nEr kan worden geconcludeerd dat...\n= It can be concluded that...\n\nEr zou meer moeten worden geinvesteerd.\n= More should be invested.\n\nEr mag hier niet worden gefotografeerd.\n= Photography is not allowed here.\n\nPattern: er + modal + worden + PP.\nVery common in news, politics, and formal writing.\nNo specific person does the action."},
        {type:"mc",q:"'De minister zei dat het plan wordt uitgevoerd.' The 'dat' clause contains:",opts:["Active voice","Present passive","Past passive","No verb"],ans:"Present passive",hint:"wordt uitgevoerd = is being implemented"},
        {type:"fb",opts:["werd","wordt","is","was"],hint:"Tense backshift in indirect speech: became",s:"De expert waarschuwde dat de situatie ernstiger ___.",a:"werd"},
        {type:"mc",q:"'Er moet worden ingegrepen' means:",opts:["He must intervene","Action must be taken","They are intervening","Intervention happened"],ans:"Action must be taken",hint:"Er + modal + worden + PP = impersonal passive"},
        {type:"drag_fill",hint:"The spokesperson reported that measures are being taken.",s:"De woordvoerder {1} dat er maatregelen worden {2}.",blanks:{"1":"meldde","2":"genomen"},pool:["meldde","genomen","zei","geschreven"]},
        {type:"fb",opts:["zou","moet","kan","mag"],hint:"Modal for obligation in conditional: er ___ meer geïnvesteerd worden",s:"Er ___ meer moeten worden geinvesteerd.",a:"zou"},
        {type:"mc",q:"'Volgens de premier moet er meer worden geinvesteerd.' Who does the investing?",opts:["The premier personally","Nobody specific (impersonal)","The journalist","The voters"],ans:"Nobody specific (impersonal)",hint:"Er-passive: no ___ agent"},
        {type:"fb",opts:["kan","moet","mag","zal"],hint:"Er ___ geconcludeerd worden dat...",s:"Er ___ worden geconcludeerd dat het plan werkt.",a:"kan"},
        {type:"drag_fill",hint:"Photography prohibited. Steps are required.",s:"Er {1} hier niet worden gefotografeerd. Er {2} worden ingegrepen.",blanks:{"1":"mag","2":"moet"},pool:["mag","moet","kan","zal"]},
        {type:"mc",q:"'De premier zei dat er meer moet worden geinvesteerd.' This combines:",opts:["Only indirect speech","Only passive voice","Indirect speech + impersonal er-passive + modal","Only a modal verb"],ans:"Indirect speech + impersonal er-passive + modal",hint:"Past tense of 'zeggen' + dat (___ ___ pattern)"},
        {type:"fb",opts:["zei","vroeg","meldde","rapporteerde"],hint:"Past tense of zeggen in reported speech",s:"De minister ___ dat het probleem wordt opgelost.",a:"zei"},
        {type:"match",pairs:[
          {trg:"Er moet worden ingegrepen.",src:"Action must be taken."},
          {trg:"Er kan worden geconcludeerd.",src:"It can be concluded."},
          {trg:"Er mag niet worden gerookt.",src:"Smoking is not allowed."},
          {trg:"Er zou meer moeten worden gedaan.",src:"More should be done."}
        ]},
        {type:"fb",opts:["ging","gaat","ga","gegaan"],hint:"Past tense of gaan, irregular verb",s:"'Ik ga morgen.' → Hij zei dat hij morgen ___.",a:"ging"},
        {type:"mc",q:"In Dutch, indirect yes/no questions like 'She asked whether...' are introduced by:",opts:["dat","of","wat","als"],ans:"of",hint:"Which conjunction introduces indirect yes/no questions?"},
        {type:"drag_fill",hint:"The journalist asked WHETHER. More SHOULD be done.",s:"De journalist {1} of de minister zou reageren. Er {2} meer moeten worden gedaan.",blanks:{"1":"vroeg","2":"zou"},pool:["vroeg","zou","zei","moet"]},
        {type:"fb",opts:["was","is","wordt","werd"],hint:"Tense shifts back: zijn in past tense",s:"'Het is een probleem.' → De expert zei dat het een probleem ___.",a:"was"}
  ]},
  {id:"v2u22l5",title:"Het Artikel Lezen",icon:"📖",xp:25,board:true,steps:[
        {type:"intro",title:"Het Artikel Lezen",desc:"Time to read a real-style Dutch news article that combines everything: advanced passive, indirect speech, news vocabulary, and formal register. You will analyze the text for grammar patterns and meaning.",goals:["Read an advanced Dutch news article","Identify passive constructions in context","Spot indirect speech patterns","Answer comprehension and grammar questions"]},
        {type:"tip",title:"📰 Lees: Nieuwe Regels voor Sociale Media",deepDive:{
          title:"Vertaling",
          text:"NEW RULES FOR SOCIAL MEDIA\n\nBy our correspondent in Brussels\n\nThe European Commission announced new rules\nfor social media yesterday. The rules were\npresented by Commissioner Jansen during a\npress conference in Brussels.\n\n'More must be done to combat fake news,'\nsaid Jansen. 'The current rules are not\nstrict enough.'\n\nAccording to the commissioner, tech companies\nare required to remove misleading content\nfaster. It was also reported that companies\nthat don't follow the rules can receive\nhigh fines.\n\nMedia experts reacted positively. 'This is an\nimportant step,' declared Professor De Vries.\nHe warned however that enforcement will\nbe difficult.\n\nThe new legislation is expected to take effect\nnext year."
        },text:"NIEUWE REGELS VOOR SOCIALE MEDIA\n\nDoor onze correspondent in Brussel\n\nDe Europese Commissie heeft gisteren nieuwe\nregels voor sociale media aangekondigd. De regels\nwerden gepresenteerd door commissaris Jansen\ntijdens een persconferentie in Brussel.\n\n'Er moet meer worden gedaan om nepnieuws\nte bestrijden,' zei Jansen. 'De huidige regels\nzijn niet streng genoeg.'\n\nVolgens de commissaris worden techbedrijven\nverplicht om misleidende content sneller te\nverwijderen. Er werd ook gemeld dat bedrijven\ndie de regels niet volgen hoge boetes kunnen\nkrijgen.\n\nMedia-experts reageerden positief. 'Dit is een\nbelangrijke stap,' verklaarde professor De Vries.\nHij waarschuwde echter dat de handhaving\nlastig zal zijn.\n\nDe nieuwe wetgeving wordt naar verwachting\nvolgend jaar van kracht."},
        {type:"mc",q:"Who presented the new rules?",opts:["Professor De Vries","Commissaris Jansen","The tech companies","The media experts"],ans:"Commissaris Jansen",hint:"The rules were presented by... (check the first paragraph)"},
        {type:"fb",opts:["werden","werd","zijn","is"],hint:"Plural past passive: de regels _____ gepresenteerd",s:"De regels ___ gepresenteerd door commissaris Jansen.",a:"werden"},
        {type:"mc",q:"'Er moet meer worden gedaan om nepnieuws te bestrijden.' This is:",opts:["A direct quote from Jansen","Indirect speech","The journalist's opinion","A headline"],ans:"A direct quote from Jansen",hint:"Inside quotation marks: 'Er moet meer worden gedaan...' zei ___"},
        {type:"fb",opts:["werd","wordt","is","zijn"],hint:"It was also reported (past passive)",s:"Er ___ ook gemeld dat bedrijven hoge boetes kunnen krijgen.",a:"werd"},
        {type:"mc",q:"In the sentence '___ worden verplicht om misleidende content te verwijderen', what is the passive subject?",opts:["De commissaris","Misleidende content","Techbedrijven","De regels"],ans:"Techbedrijven",hint:"Tech companies are required (they receive the obligation)"},
        {type:"drag_fill",hint:"He warned that enforcement will be difficult.",s:"Hij {1} dat de handhaving lastig zal {2}.",blanks:{"1":"waarschuwde","2":"zijn"},pool:["waarschuwde","zijn","meldde","worden"]},
        {type:"fb",opts:["kracht","start","regel","wet"],hint:"Van ___ worden = to take effect (power/force)",s:"De nieuwe wetgeving wordt naar verwachting volgend jaar van ___.",a:"kracht"},
        {type:"match",pairs:[
          {trg:"de persconferentie",src:"the press conference"},
          {trg:"nepnieuws bestrijden",src:"to combat fake news"},
          {trg:"misleidende content",src:"misleading content"},
          {trg:"de handhaving",src:"the enforcement"}
        ]},
        {type:"mc",q:"How many passive constructions are in the article?",opts:["Two","Three","Five or more","None"],ans:"Five or more",hint:"Past passive plural + modal passive + present passive + past passive singular + present passive"},
        {type:"fb",opts:["reageerden","reageerde","reageren","gereageerd"],hint:"Past tense plural of reageren",s:"Media-experts ___ positief op de nieuwe regels.",a:"reageerden"},
        {type:"mc",q:"'Volgens de commissaris worden techbedrijven verplicht...' starts with 'volgens' which means:",opts:["Because of","According to","Despite","Before"],ans:"According to",hint:"Attribution word: who says something"},
        {type:"drag_fill",hint:"More must be done. The rules were presented.",s:"'Er {1} meer worden gedaan,' zei Jansen. De regels {2} gepresenteerd in Brussel.",blanks:{"1":"moet","2":"werden"},pool:["moet","werden","kan","werd"]},
        {type:"fb",opts:["boetes","prijzen","artikelen","bronnen"],hint:"Financial penalties: de _____ (plural)",s:"Bedrijven die de regels niet volgen kunnen hoge ___ krijgen.",a:"boetes"},
        {type:"mc",q:"'Dit is een belangrijke stap,' verklaarde professor De Vries. 'Verklaarde' means:",opts:["Asked","Denied","Declared/stated","Whispered"],ans:"Declared/stated",hint:"Verklaren = to declare/state (formal)"},
        {type:"drag_fill",hint:"The new LEGISLATION takes EFFECT next year.",s:"De nieuwe {1} wordt naar verwachting volgend jaar van {2}.",blanks:{"1":"wetgeving","2":"kracht"},pool:["wetgeving","kracht","regel","start"]},
        {type:"fb",opts:["echter","ook","niet","wel"],hint:"Formal contrast word in news reporting",s:"Hij waarschuwde ___ dat de handhaving lastig zal zijn.",a:"echter"}
  ]},
  {id:"v2u22l6",title:"Een Samenvatting Schrijven",icon:"✍️",xp:25,board:true,steps:[
        {type:"intro",title:"Een Samenvatting Schrijven",desc:"Writing news summaries requires precise use of passive voice and indirect speech. You will practice transforming active sentences into passive, converting direct quotes to indirect speech, and structuring a summary.",goals:["Transform active → passive in news context","Convert direct → indirect speech","Use attribution phrases (volgens, aldus, zo meldde)","Structure a news summary"]},
        {type:"tip",title:"✍️ News Summary Structure",text:"A Dutch news summary follows this pattern:\n\n1. HEADLINE: Short, present tense\n'Minister kondigt nieuwe regels aan.'\n\n2. LEAD: Who, what, when, where\n'De minister heeft gisteren nieuwe regels\naangekondigd voor sociale media.'\n\n3. ATTRIBUTION: Who said what\n'Volgens de minister zijn de huidige regels\nniet streng genoeg.'\n'De woordvoerder meldde dat...'\n\n4. CONTEXT: Background\n'De regels werden al langer verwacht.'\n\n5. REACTION: Expert/public response\n'Experts reageerden positief.'\n\nKey phrases for attribution:\nvolgens... = according to...\naldus... = thus spoke... (formal)\nzo meldde... = so reported...\nnaar verluidt = reportedly"},
        {type:"teach",trg:"aldus",src:"thus spoke / so said (formal attribution)",pos:"noun",gender:null,phonetic:"AL-dus",note:"Very formal attribution word.\n'Aldus de minister' = so said the minister.\nUsed in written news, never in conversation.\nAlternative: 'zo zei de minister'.",example:"A: 'We moeten ingrijpen,' aldus de minister.\nB: Dat is een sterke uitspraak.\nA: Ja, en de media citeren het overal.\nB: Aldus is typisch krantentaal.",exampleSrc:"A: 'We must intervene,' thus spoke the minister.\nB: That's a strong statement.\nA: Yes, and the media are quoting it everywhere.\nB: 'Aldus' is typical newspaper language.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"naar verluidt",src:"reportedly / according to reports",pos:"intj",gender:null,phonetic:"nahr fur-LOWT",note:"Used when the information is not confirmed.\n'Naar verluidt' signals: this is what we hear,\nbut we don't know for certain.\nVery common in news reporting.",example:"A: Naar verluidt treedt de directeur af.\nB: Is dat bevestigd?\nA: Nee, het zijn alleen geruchten.\nB: Dan moeten we voorzichtig zijn.",exampleSrc:"A: Reportedly, the director is stepping down.\nB: Has that been confirmed?\nA: No, they're only rumors.\nB: Then we should be careful.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"mc",q:"Which phrase signals unconfirmed information?",opts:["Volgens de minister","Aldus de premier","Naar verluidt","Het is bevestigd dat"],ans:"Naar verluidt",hint:"Reportedly = not yet confirmed"},
        {type:"fb",opts:["aldus","want","omdat","maar"],hint:"Formal attribution: 'thus spoke' the minister",s:"'We moeten ingrijpen,' ___ de minister.",a:"aldus"},
        {type:"mc",q:"Active: 'De commissie schrijft het rapport.' → Passive:",opts:["Het rapport wordt geschreven door de commissie.","De commissie wordt geschreven.","Het rapport schrijft de commissie.","De commissie heeft geschreven."],ans:"Het rapport wordt geschreven door de commissie.",hint:"Object becomes subject + ___ + PP + ___"},
        {type:"drag_fill",hint:"According to the spokesperson. Reportedly.",s:"{1} de woordvoerder zijn er problemen. {2} treedt de directeur af.",blanks:{"1":"Volgens","2":"Naar verluidt"},pool:["Volgens","Naar verluidt","Aldus","Omdat"]},
        {type:"fb",opts:["was","is","wordt","werd"],hint:"Past tense of zijn, single form",s:"Direct: 'Ik ben tevreden.' → Indirect: De minister zei dat hij tevreden ___.",a:"was"},
        {type:"mc",q:"Active: 'De journalist interviewde de premier.' → Passive:",opts:["De premier werd geinterviewd door de journalist.","De journalist werd geinterviewd.","De premier heeft geinterviewd.","De journalist is geinterviewd."],ans:"De premier werd geinterviewd door de journalist.",hint:"Past active → ___ + PP + ___"},
        {type:"fb",opts:["Naar","Volgens","Bij","Over"],hint:"The two-word phrase meaning 'reportedly'",s:"___ verluidt treedt de directeur binnenkort af.",a:"Naar"},
        {type:"drag_fill",hint:"The minister said. According to the minister.",s:"De minister {1} dat er meer moet worden gedaan. {2} de minister is de situatie ernstig.",blanks:{"1":"zei","2":"Volgens"},pool:["zei","Volgens","meldde","Aldus"]},
        {type:"mc",q:"Which is the correct passive of 'De redactie publiceert het artikel'?",opts:["Het artikel wordt gepubliceerd door de redactie.","De redactie wordt gepubliceerd.","Het artikel publiceert de redactie.","De redactie is gepubliceerd."],ans:"Het artikel wordt gepubliceerd door de redactie.",hint:"Object → subject + ___ + PP + ___ agent"},
        {type:"match",pairs:[{trg:"volgens",src:"according to (named source)"},{trg:"aldus",src:"thus spoke (formal)"},{trg:"naar verluidt",src:"reportedly (unconfirmed)"},{trg:"zo meldde",src:"so reported"}]},
        {type:"fb",opts:["namen","nemen","neemt","genomen"],hint:"Past tense of nemen, strong verb",s:"Direct: 'We nemen maatregelen.' → De premier zei dat zij maatregelen ___.",a:"namen"},
        {type:"drag_fill",hint:"The PM was interviewed by the journalist (past passive).",s:"De premier {1} geinterviewd door de {2}.",blanks:{"1":"werd","2":"journalist"},pool:["werd","journalist","wordt","redactie"]},
        {type:"mc",q:"A news summary starts with a headline. Dutch headlines typically use:",opts:["Past tense","Present tense","Future tense","Passive voice only"],ans:"Present tense",hint:"Headlines describe events as if happening now"},
        {type:"fb",opts:["eens","niet","ook","wel"],hint:"Het ermee ___ zijn = to agree",s:"'Ik ben het ermee eens.' → De premier zei dat hij het ermee ___ was.",a:"eens"}
  ]},
  {id:"v2u22l7",title:"Het Nederlandse Medialandschap",icon:"🇳🇱",xp:20,board:true,steps:[
        {type:"intro",title:"Het Nederlandse Medialandschap",desc:"Understanding Dutch media means knowing the NOS, RTL, de Volkskrant, and NRC. The Netherlands has a unique public broadcasting system, a strong newspaper tradition, and very high digital media consumption.",goals:["NOS, RTL, NPO: public vs commercial broadcasting","Major newspapers: de Volkskrant, NRC, De Telegraaf, AD","Dutch press freedom tradition","Media consumption habits"]},
        {type:"tip",title:"📺 Publieke vs Commerciele Omroep",text:"PUBLIC BROADCASTING (NPO):\nNPO 1, NPO 2, NPO 3 = TV channels\nNPO Radio 1-5 = radio stations\n\nThe NOS is the news division:\n'Het NOS Journaal' = the main news broadcast\n'NOS op 3' = news for younger audiences\nThe NOS is considered the most trusted news source.\n\nUnique Dutch system: 'omroepen' (broadcasting associations)\nAVRO-TROS, BNNVARA, KRO-NCRV, VPRO, etc.\nEach has its own identity and makes programs for NPO.\n\nCOMMERCIAL:\nRTL 4, RTL 5, RTL 7 = commercial TV\nSBS 6, Veronica, Net5 = other commercial channels\n\nRTL Nieuws is the main commercial news competitor."},
        {type:"tip",title:"📰 De Grote Kranten",deepDive:{
          title:"Press Freedom in the Netherlands",
          text:"The Dutch tradition of press freedom goes back centuries. The Netherlands was one of the first countries where books and newspapers could be published relatively freely.\n\nIn the 17th century (the Golden Age), Amsterdam was the publishing capital of Europe. Books banned elsewhere in Europe were printed in Amsterdam.\n\nToday, press freedom is protected by Article 7 of the Dutch Constitution: 'No one shall require prior permission to publish thoughts or opinions through the press.'\n\nThe Netherlands consistently ranks in the top 10 of the World Press Freedom Index. Dutch journalists are rarely threatened or censored.\n\nHowever, in recent years, threats against journalists have increased, particularly crime reporters. Peter R. de Vries, a famous crime reporter, was murdered in 2021. This shocked the nation and led to new protection measures for journalists."
        },text:"Quality newspapers (broadsheets):\nNRC Handelsblad = intellectual, center-right\nde Volkskrant = progressive, center-left\nTrouw = originally Protestant, now broadly progressive\n\nPopular newspapers (tabloids):\nDe Telegraaf = largest circulation, right-leaning\nAlgemeen Dagblad (AD) = centrist, popular\n\nFree newspapers (stopped print, now digital):\nMetro = stopped in 2020\n\nRegional:\nHet Parool (Amsterdam), Brabants Dagblad,\nDagblad van het Noorden, etc.\n\nThe Netherlands has one of the highest\npress freedom rankings in the world.\n'Reporters Without Borders' consistently ranks\nthe Netherlands in the top 5-10."},
        {type:"mc",q:"The NOS is the news division of:",opts:["RTL","NPO (public broadcasting)","De Telegraaf","de Volkskrant"],ans:"NPO (public broadcasting)",hint:"NOS = Nederlandse Omroep Stichting, part of ___"},
        {type:"fb",opts:["Journaal","Nieuws","Rapport","Interview"],hint:"Het acht uur _____: the main NOS news",s:"Het NOS ___ is het belangrijkste nieuwsprogramma.",a:"Journaal"},
        {type:"match",pairs:[
          {trg:"NRC Handelsblad",src:"intellectual, center-right"},
          {trg:"de Volkskrant",src:"progressive, center-left"},
          {trg:"De Telegraaf",src:"largest, right-leaning"},
          {trg:"Algemeen Dagblad (AD)",src:"centrist, popular"}
        ]},
        {type:"mc",q:"The unique feature of Dutch public broadcasting is:",opts:["One single state-owned channel","Multiple omroepen sharing NPO","No advertising at all on any channel","Only news programs, no entertainment"],ans:"Multiple omroepen sharing NPO",hint:"AVRO-TROS, BNNVARA, VPRO all produce content for the same platform"},
        {type:"mc",q:"Which Dutch newspaper has the most readers?",opts:["NRC Handelsblad","de Volkskrant","De Telegraaf","Algemeen Dagblad"],ans:"De Telegraaf",hint:"The largest Dutch daily newspaper"},
        {type:"mc",q:"In the World Press Freedom Index, the Netherlands typically ranks:",opts:["Top 5-10","Around 50","Around 100","Not ranked"],ans:"Top 5-10",hint:"One of the highest press freedom countries"},
        {type:"fb",opts:["commerciele","openbare","gratis","grote"],hint:"Not public: a _____ omroep (profit-driven)",s:"RTL is een ___ omroep, NPO is publiek.",a:"commerciele"},
        {type:"drag_fill",hint:"The NOS evening news programme: public broadcaster",s:"Het NOS {1} is publiek. {2} Nieuws is commercieel.",blanks:{"1":"Journaal","2":"RTL"},pool:["Journaal","RTL","NRC","AD"]},
        {type:"mc",q:"Which newspaper is considered 'progressive, center-left'?",opts:["De Telegraaf","NRC Handelsblad","de Volkskrant","Algemeen Dagblad"],ans:"de Volkskrant",hint:"The 'people's newspaper' by name"},
        {type:"match",pairs:[{trg:"NPO",src:"public broadcasting"},{trg:"RTL",src:"commercial broadcasting"},{trg:"NOS",src:"news division of NPO"},{trg:"omroepen",src:"broadcasting associations"}]},
        {type:"fb",opts:["betrouwbare","commerciele","goedkope","populaire"],hint:"The most trustworthy source: te vertrouwen",s:"De NOS wordt beschouwd als de meest ___ nieuwsbron.",a:"betrouwbare"},
        {type:"mc",q:"'Omroepen' like AVRO-TROS and VPRO are:",opts:["Commercial TV channels","Newspapers","Broadcasting associations that make programs for NPO","Radio stations only"],ans:"Broadcasting associations that make programs for NPO",hint:"Each omroep has its own identity within the ___ system"},
        {type:"drag_fill",hint:"Volkskrant = progressive. Telegraaf = largest circulation.",s:"De {1} is progressief. De {2} heeft de grootste oplage.",blanks:{"1":"Volkskrant","2":"Telegraaf"},pool:["Volkskrant","Telegraaf","NRC","AD"]},
        {type:"mc",q:"The Netherlands has such high press freedom because:",opts:["There are no newspapers","A centuries-old tradition since the Golden Age","The government controls all media","Only one news channel exists"],ans:"A centuries-old tradition since the Golden Age",hint:"Amsterdam was the publishing capital of 17th-century Europe"},
        {type:"fb",opts:["zendt","zend","zenden","gezonden"],hint:"Uitzenden: separable verb. De NOS _____ om 8 uur uit.",s:"De NOS ___ uit om acht uur 's avonds.",a:"zendt"}
  ]},
  {id:"v2u22l8",title:"Unit 22 Review",icon:"🏆",xp:30,board:true,steps:[
        {type:"intro",title:"Unit 22 Review",desc:"Comprehensive review of everything from Unit 22: news vocabulary, media terminology, advanced passive voice, indirect speech in news, and Dutch media culture. Can you read, write, and discuss Dutch news?",goals:["All news and media vocabulary","Advanced passive: werd/werden, is/zijn passive","Indirect speech in news reporting","Dutch media landscape knowledge"]},
        {type:"mc",q:"'Het artikel werd gepubliceerd door de redactie.' The passive here is:",opts:["Present passive (process)","Past passive (process)","Result passive (state)","Impersonal passive"],ans:"Past passive (process)",hint:"Werd = ___ tense of worden = ___ in the ___"},
        {type:"fb",opts:["werden","werd","zijn","was"],hint:"Plural subject, past process auxiliary",s:"De brieven ___ geschreven door de studenten. (past passive, plural)",a:"werden"},
        {type:"mc",q:"'Het rapport is geschreven.' vs 'Het rapport werd geschreven.' The difference:",opts:["No difference","'is' = result (done), 'werd' = process (was being done)","'is' = present, 'werd' = future","'is' = singular, 'werd' = plural"],ans:"'is' = result (done), 'werd' = process (was being done)",hint:"Zijn passive = ___. Worden passive = ___."},
        {type:"drag_fill",hint:"The minister said that. Action must be taken.",s:"De minister {1} dat er maatregelen worden genomen. Er {2} worden ingegrepen.",blanks:{"1":"zei","2":"moet"},pool:["zei","moet","vroeg","kan"]},
        {type:"fb",opts:["Naar","Volgens","Bij","Aldus"],hint:"_____ verluidt: according to unconfirmed sources",s:"___ verluidt treedt de directeur af.",a:"Naar"},
        {type:"match",pairs:[{trg:"het nieuws",src:"the news"},{trg:"de journalist",src:"the journalist"},{trg:"de bron",src:"the source"},{trg:"betrouwbaar",src:"reliable"}]},
        {type:"mc",q:"'De woordvoerder meldde dat de situatie ernstig was.' This combines:",opts:["Only passive voice","Only indirect speech","Indirect speech with tense backshift","Direct speech"],ans:"Indirect speech with tense backshift",hint:"meldde dat (___) + was (___ from is)"},
        {type:"fb",opts:["namen","nemen","neemt","genomen"],hint:"Reporting in past: nemen shifts to past tense",s:"'We nemen maatregelen.' → De minister zei dat zij maatregelen ___.",a:"namen"},
        {type:"mc",q:"Het NOS Journaal is onderdeel van:",opts:["RTL","NPO (publieke omroep)","De Telegraaf","de Volkskrant"],ans:"NPO (publieke omroep)",hint:"NOS is the news division of ___"},
        {type:"drag_fill",hint:"Written yesterday (process). Now finished (result).",s:"Het artikel {1} gisteren geschreven. Het {2} nu af.",blanks:{"1":"werd","2":"is"},pool:["werd","is","wordt","was"]},
        {type:"fb",opts:["kan","moet","mag","zal"],hint:"Er ___ geconcludeerd worden dat...",s:"Er ___ worden geconcludeerd dat de regels werken.",a:"kan"},
        {type:"mc",q:"Which attribution phrase is most formal?",opts:["Hij zei dat","Volgens de minister","Aldus de premier","Ze vertelde dat"],ans:"Aldus de premier",hint:"___ = thus spoke (very formal, written news)"},
        {type:"match",pairs:[{trg:"de uitzending",src:"the broadcast"},{trg:"de documentaire",src:"the documentary"},{trg:"de podcast",src:"the podcast"},{trg:"de redactie",src:"the editorial team"}]},
        {type:"fb",opts:["progressieve","commerciele","conservatieve","gratis"],hint:"De Volkskrant is considered progressive",s:"De Volkskrant is een ___ krant. (progressive)",a:"progressieve"},
        {type:"mc",q:"'Er werd gemeld dat de fabriek wordt gesloten.' How many passive constructions?",opts:["One","Two","Three","None"],ans:"Two",hint:"werd gemeld (past passive) + wordt gesloten (present passive)"},
        {type:"drag_fill",hint:"According to. 'Aldus' is more formal than 'zei'.",s:"{1} de woordvoerder worden er maatregelen genomen. '{2} de minister' is formeler dan 'zei de minister'.",blanks:{"1":"Volgens","2":"Aldus"},pool:["Volgens","Aldus","Naar","Want"]},
        {type:"fb",opts:["werden","werd","zijn","is"],hint:"Plural rules, past tense process auxiliary",s:"De regels ___ gepresenteerd door de commissaris. (past passive, plural)",a:"werden"},
        {type:"mc",q:"'Objectieve verslaggeving' is important because:",opts:["It makes news entertaining","It ensures unbiased, fair reporting","It makes articles longer","It increases advertising revenue"],ans:"It ensures unbiased, fair reporting",hint:"Objectief = objective/___"},
        {type:"match",pairs:[
          {trg:"wordt geschreven (present passive)",src:"is being written"},
          {trg:"werd geschreven (past passive)",src:"was being written"},
          {trg:"is geschreven (result passive)",src:"has been written"},
          {trg:"moet worden geschreven (modal passive)",src:"must be written"}
        ]}
  ]}
]};
